// src/commands/auth/login.ts
async function loginCommand() {
  const { username, password } = await inquirer.prompt([
    {
      type: "input",
      name: "username",
      message: "Email:",
      validate: (v) => v.length > 0 || "Required"
    },
    {
      type: "password",
      name: "password",
      message: "Password:",
      mask: "*",
      validate: (v) => v.length > 0 || "Required"
    }
  ]);
  try {
    const encryptedPassword = encryptPassword(password);
    const res = await passportApi.post("/doLogin", {
      username,
      password: encryptedPassword,
      client_id: "02a6af67d3264a4188b04aac8ba0c496",
      from: "openapi-ai-inside",
      remember_me: "on",
      response_type: "TOKEN"
    });
    const { token, errcode } = res.data;
    if (errcode || !token) {
      error(`Login failed: ${errcode ?? "unknown error"}`);
      process.exit(1);
    }
    await saveToken(token);
    const payload = JSON.parse(
      Buffer.from(token.split(".")[1], "base64url").toString()
    );
    saveConfig({
      userId: payload.user_id ?? payload.sub ?? "",
      email: payload.email ?? username,
      tenantId: payload.tenant_id
    });
    success(`Logged in as ${payload.email ?? username}`);
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    error(`Login failed: ${msg}`);
    process.exit(1);
  }
}

// src/commands/auth/logout.ts
async function logoutCommand() {
  await deleteToken();
  deleteConfig();
  success("Logged out");
}

// src/commands/auth/whoami.ts
async function whoamiCommand() {
  const token = await getToken();
  if (!token) {
    info("Not logged in. Run: patsnap login");
    return;
  }
  const config = getConfig();
  if (!config) {
    info("Not logged in. Run: patsnap login");
    return;
  }
  outputDetail({
    data: {
      email: config.email,
      userId: config.userId,
      ...config.tenantId ? { tenantId: config.tenantId } : {}
    }
  });
}

// src/commands/apikey.ts
import inquirer2 from "inquirer";
async function apikeyListCommand() {
  try {
    const api = await authedRequest();
    const res = await api.get("/manager/person-center/api-keys");
    const keys = res.data?.data ?? [];
    if (keys.length === 0) {
      info("No API keys found. Create one with: patsnap apikey create");
      return;
    }
    console.log("\n  Name                  API Key                                            Created");
    console.log("  " + "\u2500".repeat(80));
    for (const k of keys) {
      const name = k.name.padEnd(22);
      const key = k.api_key.padEnd(51);
      const created = k.created_at;
      console.log(`  ${name}${key}${created}`);
    }
    console.log();
  } catch (err) {
    error(err.message);
    process.exit(1);
  }
}
async function apikeyCreateCommand() {
  const { name } = await inquirer2.prompt([
    {
      type: "input",
      name: "name",
      message: "API Key name:",
      validate: (v) => v.length > 0 || "Required"
    }
  ]);
  try {
    const api = await authedRequest();
    const res = await api.post("/openapi/apikey/create", { name });
    const key = res.data?.data?.key;
    if (!key) {
      error("Failed to create API key");
      process.exit(1);
    }
    success("API Key created (save it now \u2014 it won't be shown again):");
    console.log("\n  " + key + "\n");
  } catch (err) {
    error(err.message);
    process.exit(1);
  }
}

